 // microfacet distribution\n    float d = D_GGX(NdotH, mat.alphaRoughness);\n    //float d = D_GGXFast(n, NdotH, mat.alphaRoughness, h);\n    // Lambertian diffuse brdf\n    vec3 diffuseTerm = (1.0 - f) * diffuseLambertian(mat);\n    // Cook-Torrance BRDF\n    vec3 specularTerm = f * g * d;\n\n    vec3 transformed_normal = vec3(-n.xy, n.z);\n\n    float lighting_factor;\n#ifdef RENDER_SHADOWS\n    lighting_factor = shadowed_light_factor_normal(transformed_normal, v_pos_light_view_0, v_pos_light_view_1, v_depth_shadows);\n#else\n    lighting_factor = NdotL;\n#endif // RENDER_SHADOWS\n\n    vec3 directLightColor = (specularTerm + diffuseTerm) * lighting_factor * lightColor;\n    vec3 indirectLightColor = computeIndirectLightContribution(mat, NdotV, transformed_normal);\n\n    vec3 color = (saturate(directLightColor) + indirectLightColor);\n\n    float intensityFactor = 1.0;\n#if !defined(LIGHTING_3D_MODE)\n    const vec3 luminosityFactor = vec3(0.2126, 0.7152, 0.0722);\n\n    // Calculate luminance\n    float luminance = dot(diffuseTerm, luminosityFactor);\n    // Adjust light intensity depending on light incidence\n    intensityFactor = mix((1.0 - u_lightintensity), max((1.0 - luminance + u_lightintensity), 1.0), NdotL);\n#endif // !defined(LIGHTING_3D_MODE)\n\n    color *= intensityFactor;\n    return color;\n}\n\nvoid main() {\n\n#ifdef TERRAIN_FRAGMENT_OCCLUSION\n    if (isOccluded()) {\n        discard;\n    }\n#endif\n\n    vec3 lightDir = u_lightpos;\n    vec3 lightColor = u_lightcolor;\n\n#ifdef LIGHTING_3D_MODE\n    lightDir = u_lighting_directional_dir;\n    // invert xy  as they are flipped for fill extrusion normals (compared to expected here) and,\n    // as a new citizen, better to not change legacy code convention.\n    lightDir.xy = -lightDir.xy;\n    lightColor = u_lighting_directional_color;\n#endif\n\nvec4 finalColor;\n#ifdef DIFFUSE_SHADED\n    vec3 N = getNormal();\n    vec3 baseColor = getBaseColor().rgb;\n    vec3 diffuse = getDiffuseShadedColor(baseColor, N, lightDir, lightColor);\n    // Ambient Occlusion\n#ifdef HAS_TEXTURE_u_occlusionTexture\n    // For b3dm tiles where models contains occlusion textures we interpret them similarly to how\n    // we handle baseColorTexture as an alpha mask (i.e one channel).\n    // This is why we read the alpha component here (refer to getBaseColor to see how baseColorTexture.w is used to implement alpha masking).\n    float ao = (texture(u_occlusionTexture, uv_2f).r - 1.0) * u_aoIntensity + 1.0;\n    diffuse *= ao;\n#endif\n    finalColor = vec4(mix(diffuse, baseColor, u_emissive_strength), 1.0) * u_opacity;\n#else // DIFFUSE_SHADED\n    Material mat = getPBRMaterial();\n    vec3 color = computeLightContribution(mat, lightDir, lightColor);\n\n    // Ambient Occlusion\n    float ao = 1.0;\n#if defined (HAS_TEXTURE_u_occlusionTexture) && defined(HAS_ATTRIBUTE_a_uv_2f)\n\n#ifdef OCCLUSION_TEXTURE_TRANSFORM\n    vec2 uv = uv_2f.xy * u_occlusionTextureTransform.zw + u_occlusionTextureTransform.xy;\n#else\n    vec2 uv = uv_2f;\n#endif\n    ao = (texture(u_occlusionTexture, uv).x - 1.0) * u_aoIntensity + 1.0;\n    color *= ao;\n#endif\n    // Emission\n    vec4 emissive = u_emissiveFactor;\n\n#if defined(HAS_TEXTURE_u_emissionTexture) && defined(HAS_ATTRIBUTE_a_uv_2f)\n    emissive.rgb *= sRGBToLinear(texture(u_emissionTexture, uv_2f).rgb);\n#endif\n#ifdef APPLY_LUT_ON_GPU\n    // Note: the color is multiplied by the length of u_emissiveFactor\n    // which avoids increasing the brightness if the LUT doesn\'t have pure black.\n    float emissiveFactorLength = max(length(u_emissiveFactor.rgb), 0.001);\n    emissive.rgb = sRGBToLinear(applyLUT(u_lutTexture, linearTosRGB(emissive.rgb / emissiveFactorLength).rbg)) * emissiveFactorLength;\n#endif\n    color += emissive.rgb;\n\n    // Apply transparency\n    float opacity = mat.baseColor.w * u_opacity;\n#ifdef HAS_ATTRIBUTE_a_pbr\n    float resEmission = v_roughness_metallic_emissive_alpha.z;\n\n    resEmission *= v_height_based_emission_params.z + v_height_based_emission_params.w * pow(clamp(v_height_based_emission_params.x, 0.0, 1.0), v_height_based_emission_params.y);\n\n    vec3 color_mix = v_color_mix.rgb;\n#ifdef APPLY_LUT_ON_GPU\n    color_mix = applyLUT(u_lutTexture, color_mix);\n#endif\n    color = mix(color, color_mix, min(1.0, resEmission));\n#ifdef HAS_ATTRIBUTE_a_color_4f\n    // pbr includes color. If pbr is used, color_4f is used to pass information about light geometry.\n    // calculate distance to line segment, multiplier 1.3 additionally deattenuates towards extruded corners.\n    float distance = length(vec2(1.3 * max(0.0, abs(color_4f.x) - color_4f.z), color_4f.y));\n    distance +=  mix(0.5, 0.0, clamp(resEmission - 1.0, 0.0, 1.0));\n    opacity *= v_roughness_metallic_emissive_alpha.w * saturate(1.0 - distance * distance);\n#endif\n#endif\n    // Use emissive strength as interpolation between lit and unlit color\n    // for coherence with other layer types.\n    vec3 unlitColor = mat.baseColor.rgb * ao + emissive.rgb;\n    color = mix(color, unlitColor, u_emissive_strength);\n    color = linearTosRGB(color);\n    color *= opacity;\n    finalColor = vec4(color, opacity);\n#endif // !DIFFUSE_SHADED\n\n#ifdef FOG\n    finalColor = fog_dither(fog_apply_premultiplied(finalColor, v_fog_pos, v_position_height.w));\n#endif\n\n#ifdef RENDER_CUTOFF\n    finalColor *= v_cutoff_opacity;\n#endif\n\n#ifdef INDICATOR_CUTOUT\n    finalColor = applyCutout(finalColor, v_position_height.w);\n#endif\n\n    glFragColor = finalColor;\n\n#ifdef OVERDRAW_INSPECTOR\n    glFragColor = vec4(1.0);\n#endif\n\n    HANDLE_WIREFRAME_DEBUG;\n}\n','#include "_prelude_fog.vertex.glsl"\n#include "_prelude_shadow.vertex.glsl"\n\nin vec3 a_pos_3f;\n\n#pragma mapbox: define-attribute highp vec3 normal_3f\n#pragma mapbox: define-attribute highp vec2 uv_2f\n#pragma mapbox: define-attribute highp vec3 color_3f\n#pragma mapbox: define-attribute highp vec4 color_4f\n#pragma mapbox: define-attribute-vertex-shader-only highp vec4 pbr\n#pragma mapbox: define-attribute-vertex-shader-only highp vec3 heightBasedEmissiveStrength\n\n// pbr\n// .xy - color.rgba (4 bytes)\n// .z - emissive strength (1 byte) | roughness (4 bits) | metallic (4 bits)\n// .w - heightBasedEmissionMultiplier value at interpolation Begin and Finish points (2 bytes)\n\n// heightBasedEmissiveStrength\n// .xy - interpolation parameters\n// .z - interpolation curve power\n// i.e.\n// interpolatedHeight = pow(pos_z * .x + .y, .z)\n\nuniform mat4 u_matrix;\nuniform mat4 u_node_matrix;\nuniform mat4 u_lighting_matrix;\nuniform vec3 u_camera_pos;\nuniform vec4 u_color_mix;\n\n#ifdef INSTANCED_ARRAYS\nin vec4 a_normal_matrix0;\nin vec4 a_normal_matrix1;\nin vec4 a_normal_matrix2;\nin vec4 a_normal_matrix3;\n#else\nuniform highp mat4 u_normal_matrix;\n#endif\n\n#ifdef RENDER_SHADOWS\nuniform mat4 u_light_matrix_0;\nuniform mat4 u_light_matrix_1;\nout highp vec4 v_pos_light_view_0;\nout highp vec4 v_pos_light_view_1;\nout float v_depth_shadows;\n#endif\n\nout vec4 v_position_height;\nout lowp vec4 v_color_mix;\n\n#ifdef TERRAIN_FRAGMENT_OCCLUSION\nout highp float v_depth;\n#endif\n\n#ifdef HAS_ATTRIBUTE_a_pbr\nout lowp vec4 v_roughness_metallic_emissive_alpha;\nout mediump vec4 v_height_based_emission_params;\n// .x - height-based interpolation factor\n// .y - interpolation power\n// .z - min value\n// .w - max - min\n#endif\n\n// sRGB to linear approximation\nvec3 sRGBToLinear(vec3 srgbIn) {\n    return pow(srgbIn, vec3(2.2));\n}\n\nvoid main() {\n    #pragma mapbox: initialize-attribute highp vec3 normal_3f\n    #pragma mapbox: initialize-attribute highp vec2 uv_2f\n    #pragma mapbox: initialize-attribute highp vec3 color_3f\n    #pragma mapbox: initialize-attribute highp vec4 color_4f\n    #pragma mapbox: initialize-attribute-custom highp vec4 pbr\n    #pragma mapbox: initialize-attribute-custom highp vec3 heightBasedEmissiveStrength\n\n    highp mat4 normal_matrix;\n#ifdef INSTANCED_ARRAYS\n    normal_matrix = mat4(a_normal_matrix0, a_normal_matrix1, a_normal_matrix2, a_normal_matrix3);\n#else\n    normal_matrix = u_normal_matrix;\n#endif\n\n    vec3 local_pos;\n    mat3 rs;\n#ifdef MODEL_POSITION_ON_GPU\n    vec3 pos_color = normal_matrix[0].xyz;\n    vec4 translate = normal_matrix[1];\n    vec3 pos_a = floor(pos_color);\n    vec3 rgb = 1.05 * (pos_color - pos_a);\n    float hidden = float(pos_a.x > EXTENT);\n    float color_mix = pos_a.z / 100.0;\n    v_color_mix = vec4(sRGBToLinear(rgb), color_mix);\n\n    float meter_to_tile = normal_matrix[0].w;\n    vec4 pos = vec4(pos_a.xy, translate.z, 1.0);\n\n    rs[0].x = normal_matrix[1].w;\n    rs[0].yz = normal_matrix[2].xy;\n    rs[1].xy = normal_matrix[2].zw;\n    rs[1].z = normal_matrix[3].x;\n    rs[2].xyz = normal_matrix[3].yzw;\n\n    vec4 pos_node = u_lighting_matrix * vec4(a_pos_3f, 1.0);\n    vec3 rotated_pos_node = rs * pos_node.xyz;\n    vec3 pos_model_tile = (rotated_pos_node + vec3(translate.xy, 0.0)) * vec3(meter_to_tile, meter_to_tile, 1.0);\n\n    pos.xyz += pos_model_tile;\n    local_pos = pos.xyz;\n\n    gl_Position = mix(u_matrix * pos, AWAY, hidden);\n    pos.z *= meter_to_tile;\n    v_position_height.xyz = pos.xyz - u_camera_pos;\n#else\n    local_pos = a_pos_3f;\n    gl_Position = u_matrix * vec4(a_pos_3f, 1);\n    v_position_height.xyz = vec3(u_lighting_matrix * vec4(a_pos_3f, 1));\n    v_color_mix = vec4(sRGBToLinear(u_color_mix.rgb), u_color_mix.a);\n#endif\n    v_position_height.w = a_pos_3f.z;\n#ifdef HAS_ATTRIBUTE_a_pbr\n    vec4 albedo_c = decode_color(pbr.xy);\n\n    vec2 e_r_m = unpack_float(pbr.z);\n    vec2 r_m =  unpack_float(e_r_m.y * 16.0);\n    r_m.r = r_m.r * 16.0;\n\n    // Note: the decoded color is in linear color space\n    v_color_mix = vec4(albedo_c.rgb, 1.0); // vertex color is computed on CPU\n    v_roughness_metallic_emissive_alpha = vec4(vec3(r_m, e_r_m.x) / 255.0, albedo_c.a);\n    v_roughness_metallic_emissive_alpha.z *= 2.0; // range [0..2] was shrank to fit [0..1]\n\n    float heightBasedRelativeIntepolation = a_pos_3f.z * heightBasedEmissiveStrength.x + heightBasedEmissiveStrength.y;\n\n    v_height_based_emission_params.x = heightBasedRelativeIntepolation;\n    v_height_based_emission_params.y = heightBasedEmissiveStrength.z;\n\n    vec2 emissionMultiplierValues = unpack_float(pbr.w) / 256.0;\n\n    v_height_based_emission_params.z = emissionMultiplierValues.x;\n    v_height_based_emission_params.w = emissionMultiplierValues.y - emissionMultiplierValues.x;\n#endif\n#ifdef FOG\n    v_fog_pos = fog_position(local_pos);\n#endif\n\n#ifdef RENDER_CUTOFF\n    v_cutoff_opacity = cutoff_opacity(u_cutoff_params, gl_Position.z);\n#endif\n\n#ifdef TERRAIN_FRAGMENT_OCCLUSION\n    v_depth = gl_Position.z / gl_Position.w;\n#endif\n\n#ifdef HAS_ATTRIBUTE_a_normal_3f\n#ifdef MODEL_POSITION_ON_GPU\n    float x_squared_scale = dot(rs[0], rs[0]);\n    float y_squared_scale = dot(rs[1], rs[1]);\n    float z_squared_scale = dot(rs[2], rs[2]);\n    // https://lxjk.github.io/2017/10/01/Stop-Using-Normal-Matrix.html\n    vec3 squared_scale = vec3(x_squared_scale, y_squared_scale, z_squared_scale);\n    normal_3f = rs * ((u_lighting_matrix * vec4(normal_3f, 0.0)).xyz / squared_scale);\n    normal_3f = normalize(normal_3f);\n#else\n    normal_3f = vec3(normal_matrix * vec4(normal_3f, 0));\n#endif\n#endif\n\n#ifdef HAS_ATTRIBUTE_a_pbr\n#ifdef HAS_ATTRIBUTE_a_color_4f\n    v_roughness_metallic_emissive_alpha.w = clamp(color_4f.a * v_roughness_metallic_emissive_alpha.w * (v_roughness_metallic_emissive_alpha.z - 1.0), 0.0, 1.0);\n#endif\n#endif\n\n#ifdef RENDER_SHADOWS\n    vec4 shadow_pos = u_node_matrix * vec4(local_pos, 1.0);\n#ifdef NORMAL_OFFSET\n#ifdef HAS_ATTRIBUTE_a_normal_3f\n#ifdef MODEL_POSITION_ON_GPU\n    // flip the xy to bring it to the same, wrong, fill extrusion normal orientation toward inside.\n    // See the explanation in shadow_normal_offset.\n    vec3 offset = shadow_normal_offset(vec3(-normal_3f.xy, normal_3f.z));\n    shadow_pos.xyz += 